package com.chaobo.scm.supplier.application.integration;
import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.springframework.stereotype.Service;import tools.jackson.core.JacksonException;import tools.jackson.databind.ObjectMapper;
@Service public class IntegrationCommandEnqueuer{private final IntegrationCommandRepository repo;private final IdentifierGenerator ids;private final ObjectMapper json;public IntegrationCommandEnqueuer(IntegrationCommandRepository repo,IdentifierGenerator ids,ObjectMapper json){this.repo=repo;this.ids=ids;this.json=json;}public void enqueue(String type,String aggregateType,long aggregateId,int version,String target,Object payload){long id=ids.nextId();repo.save(new IntegrationCommand(id,"IC-"+id,type,aggregateType,aggregateId,version,target,write(payload),1,0,null,null,null));}private String write(Object value){try{return json.writeValueAsString(value);}catch(JacksonException e){throw new IllegalStateException("集成命令序列化失败",e);}}}
